def average(nums):
    """Return the arithmetic mean of nums as a float."""
    return sum(nums) / len(nums)

def dedupe(items):
    """Remove duplicate items while preserving original order."""
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

def partition(items, n):
    """Split items into n roughly-equal chunks.

    The last chunk should receive any remainder so all items end up somewhere.
    """
    if n <= 0:
        raise ValueError("n must be positive")
    if n == 1:
        return [items]

    k = len(items) // n
    result = []
    for i in range(n):
        start = i * k
        end = start + k if i < n - 1 else len(items)
        result.append(items[start:end])
    return result

def count_vowels(s):
    """Return the number of vowels in s. Case-insensitive."""
    return sum(1 for c in s.lower() if c in "aeiou")
